final:
module RefModule (
    input clk,
    input load,
    input reset,
    input [3:0] D,
    output reg [3:0] Q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset)
            Q <= 4'b0000;
        else if (load)
            Q <= D;
    end

endmodule
